package com.auction.server.service;

import com.auction.server.manage.UserManage;
import com.auction.server.models.User.User;
import com.auction.server.models.User.UserFactory;
import com.auction.server.exception.AuthenticationException;

import java.util.HashMap;
import java.util.Map;
import java.util.UUID;

/**
 * AuthService - Xử lý logic Authentication (Register, Login, Logout, Session)
 * Không dùng Singleton - có thể tạo nhiều instance
 */
public class AuthService {
    private final UserManage userManage = UserManage.getInstance();

    // Session storage: userId → token
    private final Map<String, String> activeSessions = new HashMap<>();

    private static final String EMAIL_REGEX = "^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+$";
    private static final int PASSWORD_MIN_LENGTH = 8;

    // ========== PUBLIC METHODS ==========

    /**
     *  REGISTER - Đăng ký người dùng mới
     * @param username Username (duy nhất)
     * @param password Mật khẩu
     * @param confirmPassword Xác nhận mật khẩu
     * @param email Email (duy nhất)
     * @param role ADMIN, SELLER, hoặc BIDDER
     * @return User object nếu thành công
     * @throws AuthenticationException nếu validate fail
     */
    public synchronized User register(String username, String password, String confirmPassword, 
                                       String email, String role) throws AuthenticationException {
        // 1. Validate input
        if (username == null || username.trim().isEmpty()) {
            throw new AuthenticationException("Lỗi: Username không được null hoặc rỗng");
        }
        if (password == null || password.isEmpty()) {
            throw new AuthenticationException("Lỗi: Mật khẩu không được null hoặc rỗng");
        }
        if (!password.equals(confirmPassword)) {
            throw new AuthenticationException("Lỗi: Mật khẩu xác nhận không khớp");
        }
        if (!isPasswordValid(password)) {
            throw new AuthenticationException("Lỗi: Mật khẩu phải có ít nhất " + PASSWORD_MIN_LENGTH + " ký tự");
        }
        if (!isEmailFormatValid(email)) {
            throw new AuthenticationException("Lỗi: Email không hợp lệ (phải có dấu @)");
        }
        if (role == null || role.trim().isEmpty()) {
            throw new AuthenticationException("Lỗi: Role không được null hoặc rỗng");
        }

        // 2. Tạo user object theo role
        User newUser;
        try {
            newUser = UserFactory.createUser(username, password, email, role);
        } catch (IllegalArgumentException e) {
            throw new AuthenticationException("Lỗi: " + e.getMessage());
        }

        // 3. Lưu vào UserManage (sẽ check username/email trùng)
        if (!userManage.addUser(newUser)) {
            throw new AuthenticationException("Lỗi: Không thể đăng ký. Username hoặc Email có thể đã tồn tại");
        }

        System.out.println("[AuthService] ✅ Đăng ký thành công: " + username + " (Role: " + role + ")");
        return newUser;
    }

    /**
     *  LOGIN - Đăng nhập
     * @param usernameOrEmail Username hoặc Email
     * @param password Mật khẩu
     * @return User object nếu thành công (Client lưu userId + token từ getToken())
     * @throws AuthenticationException nếu username/password sai
     */
    public synchronized User login(String usernameOrEmail, String password) throws AuthenticationException {
        if (usernameOrEmail == null || usernameOrEmail.isEmpty()) {
            throw new AuthenticationException("Lỗi: Username/Email không được null hoặc rỗng");
        }
        if (password == null || password.isEmpty()) {
            throw new AuthenticationException("Lỗi: Mật khẩu không được null hoặc rỗng");
        }

        // 1. Tìm user theo username hoặc email
        User user = userManage.getUserByUsername(usernameOrEmail);
        if (user == null) {
            user = userManage.getUserByEmail(usernameOrEmail);
        }
        if (user == null) {
            throw new AuthenticationException("Lỗi: Username/Email không tồn tại");
        }

        // 2. Kiểm tra password
        if (!user.checkpassword(password)) {
            throw new AuthenticationException("Lỗi: Mật khẩu sai");
        }

        // 3. Tạo token & lưu session
        String token = generateToken();
        activeSessions.put(user.getId(), token);

        System.out.println("[AuthService] ✅ Đăng nhập thành công: " + user.getUsername());
        System.out.println("[AuthService]  Token: " + token.substring(0, 8) + "...");
        System.out.println("[AuthService]  Tổng user online: " + activeSessions.size());

        return user;
    }

    /**
     *  LOGOUT - Đăng xuất (Xóa session)
     * @param userId ID của user cần đăng xuất
     * @throws AuthenticationException nếu userId không có session
     */
    public synchronized void logout(String userId) throws AuthenticationException {
        if (userId == null || userId.isEmpty()) {
            throw new AuthenticationException("Lỗi: User ID không được null hoặc rỗng");
        }
        if (!activeSessions.containsKey(userId)) {
            throw new AuthenticationException("Lỗi: User không đăng nhập hoặc session đã hết");
        }

        activeSessions.remove(userId);
        System.out.println("[AuthService] ✅ Đăng xuất thành công: " + userId);
        System.out.println("[AuthService]  Tổng user online: " + activeSessions.size());
    }

    /**
     * ✅ VERIFY SESSION - Kiểm tra session còn valid không
     * (Gọi mỗi lần client gửi request)
     * @param userId ID của user
     * @param token Token hiện tại
     * @return true nếu session valid
     * @throws AuthenticationException nếu session không valid
     */
    public boolean isSessionValid(String userId, String token) throws AuthenticationException {
        if (userId == null || userId.isEmpty()) {
            throw new AuthenticationException("Lỗi: User ID không được null hoặc rỗng");
        }
        if (token == null || token.isEmpty()) {
            throw new AuthenticationException("Lỗi: Token không được null hoặc rỗng");
        }

        String liveToken = activeSessions.get(userId);
        if (liveToken == null) {
            throw new AuthenticationException("Lỗi: Session không tồn tại. Vui lòng đăng nhập lại");
        }
        if (!liveToken.equals(token)) {
            throw new AuthenticationException("Lỗi: Token không khớp hoặc hết hạn");
        }

        return true;
    }

    /**
     *  CHANGE PASSWORD - Thay đổi mật khẩu
     * @param userId ID của user
     * @param oldPassword Mật khẩu cũ
     * @param newPassword Mật khẩu mới
     * @return true nếu thành công
     * @throws AuthenticationException nếu không hợp lệ
     */
    public synchronized boolean changePassword(String userId, String oldPassword, 
                                                String newPassword) throws AuthenticationException {
        if (userId == null || userId.isEmpty()) {
            throw new AuthenticationException("Lỗi: User ID không được null hoặc rỗng");
        }

        User user = userManage.getUser(userId);
        if (user == null) {
            throw new AuthenticationException("Lỗi: User không tồn tại");
        }

        // Kiểm tra mật khẩu cũ
        if (!user.checkpassword(oldPassword)) {
            throw new AuthenticationException("Lỗi: Mật khẩu cũ không chính xác");
        }

        // Kiểm tra mật khẩu mới hợp lệ
        if (!isPasswordValid(newPassword)) {
            throw new AuthenticationException("Lỗi: Mật khẩu mới phải có ít nhất " + PASSWORD_MIN_LENGTH + " ký tự");
        }

        System.out.println("[AuthService] ✅ Thay đổi mật khẩu thành công: " + user.getUsername());
        return true;
    }

    /**
     *  GET TOKEN - Lấy token của user (sau khi login thành công)
     * @param userId ID của user
     * @return Token string
     */
    public String getToken(String userId) {
        return activeSessions.get(userId);
    }

    /**
     *  GET ONLINE COUNT - Lấy số user đang online
     * @return Số user hiện tại có session active
     */
    public int getOnlineUserCount() {
        return activeSessions.size();
    }

    // ========== PRIVATE HELPER METHODS ==========

    /**
     * Kiểm tra định dạng email (regex)
     */
    private boolean isEmailFormatValid(String email) {
        if (email == null || email.isEmpty()) {
            return false;
        }
        return email.matches(EMAIL_REGEX);
    }

    /**
     * Kiểm tra mật khẩu hợp lệ (độ dài tối thiểu)
     */
    private boolean isPasswordValid(String password) {
        return password != null && password.length() >= PASSWORD_MIN_LENGTH;
    }

    /**
     * Tạo token random (UUID)
     * Ví dụ: "e7c1a88f-82d5-4a1e-8fae-1c2b3d4e5f6g"
     */
    private String generateToken() {
        return UUID.randomUUID().toString();
    }
}

package com.auction.config;

import com.zaxxer.hikari.HikariConfig;
import com.zaxxer.hikari.HikariDataSource;
import io.github.cdimascio.dotenv.Dotenv;

import java.sql.Connection;
import java.sql.SQLException;

public class DatabaseConnection {
    private static final HikariDataSource dataSource;
    private static final String DEFAULT_JDBC_URL = "jdbc:mysql://localhost:3306/auction_system";
    private static final String DEFAULT_USERNAME = "root";
    private static final String DEFAULT_PASSWORD = "123456";
    private static final Dotenv dotenv = Dotenv.configure().ignoreIfMissing().load();
    private static final HikariConfig config ;

    static {
        try {
            config = new HikariConfig();

            // 1. Set credentials và URL trước
            String jdbcUrl = resolveJdbcUrl();
            String username = resolveDbUsername();
            String password = resolveDbPassword();

            config.setJdbcUrl(jdbcUrl);
            config.setUsername(username);
            config.setPassword(password);

            // 2. Cấu hình tối ưu cho Connection Pool TRƯỚC khi tạo datasource
            config.addDataSourceProperty("cachePrepStmts", "true");
            config.addDataSourceProperty("prepStmtCacheSize", "250");
            config.addDataSourceProperty("prepStmtCacheSqlLimit", "2048");
            config.addDataSourceProperty("useSSL", "true");
            config.addDataSourceProperty("allowPublicKeyRetrieval", "true");
            config.addDataSourceProperty("serverTimezone", "UTC");
            config.setMaximumPoolSize(10); // Tối đa 10 kết nối cùng lúc
            config.setMinimumIdle(5); // Tối thiểu 5 kết nối idle
            config.setConnectionTimeout(30000); // 30 seconds
            config.setIdleTimeout(600000); // 10 minutes
            config.setMaxLifetime(1800000); // 30 minutes

            // 3. TẠO DATASOURCE LẦN NỊ sau khi đã config xong
            dataSource = new HikariDataSource(config);

            System.out.println("[DatabaseConnection] ✅ Kết nối database thành công!");
            System.out.println("[DatabaseConnection]  URL: " + jdbcUrl);
            System.out.println("[DatabaseConnection]  Username: " + username);
            System.out.println("[DatabaseConnection]  Pool Size: " + config.getMaximumPoolSize());

        } catch (Exception e) {
            System.err.println("[DatabaseConnection] ❌ Lỗi khởi tạo database connection:");
            System.err.println("[DatabaseConnection] " + e.getMessage());
            e.printStackTrace();
            throw new RuntimeException("Không thể khởi tạo database connection pool", e);
        }
    }

    private DatabaseConnection() {} // Chống khởi tạo từ bên ngoài

    public static Connection getConnection() throws SQLException {
        return dataSource.getConnection();
    }

    private static String resolveJdbcUrl() {
        String directUrl = firstNonBlank(
                dotenv.get("AUCTION_DB_URL"),
                dotenv.get("DB_URL")
        );
        if (directUrl != null) {
            return directUrl;
        }

        String host = firstNonBlank(
                dotenv.get("AUCTION_DB_HOST"),
                dotenv.get("DB_HOST")
        );
        String port = firstNonBlank(
                dotenv.get("AUCTION_DB_PORT"),
                dotenv.get("DB_PORT")
        );
        String name = firstNonBlank(
                dotenv.get("AUCTION_DB_NAME"),
                dotenv.get("DB_NAME")
        );

        if (host == null || name == null) {
            return DEFAULT_JDBC_URL;
        }

        String resolvedPort = port == null ? "3306" : port;
        return "jdbc:mysql://" + host + ":" + resolvedPort + "/" + name;
    }

    private static String resolveDbUsername() {
        return firstNonBlank(
                dotenv.get("AUCTION_DB_USERNAME"),
                dotenv.get("DB_USER"),
                dotenv.get("DB_USERNAME"),
                DEFAULT_USERNAME
        );
    }

    private static String resolveDbPassword() {
        return firstNonBlank(
                dotenv.get("AUCTION_DB_PASSWORD"),
                dotenv.get("DB_PASSWORD"),
                DEFAULT_PASSWORD
        );
    }

    private static String firstNonBlank(String... values) {
        if (values == null) {
            return null;
        }
        for (String value : values) {
            if (value != null && !value.isBlank()) {
                return value;
            }
        }
        return null;
    }
}

package com.auction.config;

import com.zaxxer.hikari.HikariConfig;
import com.zaxxer.hikari.HikariDataSource;
import io.github.cdimascio.dotenv.Dotenv;

import java.sql.Connection;
import java.sql.SQLException;

public class DatabaseConnection {
    private static final HikariDataSource dataSource;
    private static final String DEFAULT_JDBC_URL = "jdbc:mysql://localhost:3306/auction_system";
    private static final String DEFAULT_USERNAME = "root";
    private static final String DEFAULT_PASSWORD = "123456";
    private static final Dotenv dotenv = Dotenv.configure().ignoreIfMissing().load();
    private static final HikariConfig config ;

    static {
        try {
            config = new HikariConfig();

            // 1. Set credentials và URL trước
            String jdbcUrl = resolveJdbcUrl();
            String username = resolveDbUsername();
            String password = resolveDbPassword();

            config.setJdbcUrl(jdbcUrl);
            config.setUsername(username);
            config.setPassword(password);

            // 2. Cấu hình tối ưu cho Connection Pool TRƯỚC khi tạo datasource
            config.addDataSourceProperty("cachePrepStmts", "true");
            config.addDataSourceProperty("prepStmtCacheSize", "250");
            config.addDataSourceProperty("prepStmtCacheSqlLimit", "2048");
            config.addDataSourceProperty("useSSL", "true");
            config.addDataSourceProperty("allowPublicKeyRetrieval", "true");
            config.addDataSourceProperty("serverTimezone", "UTC");
            config.setMaximumPoolSize(10); // Tối đa 10 kết nối cùng lúc
            config.setMinimumIdle(5); // Tối thiểu 5 kết nối idle
            config.setConnectionTimeout(30000); // 30 seconds
            config.setIdleTimeout(600000); // 10 minutes
            config.setMaxLifetime(1800000); // 30 minutes

            // 3. TẠO DATASOURCE LẦN NỊ sau khi đã config xong
            dataSource = new HikariDataSource(config);

            System.out.println("[DatabaseConnection] ✅ Kết nối database thành công!");
            System.out.println("[DatabaseConnection]  URL: " + jdbcUrl);
            System.out.println("[DatabaseConnection]  Username: " + username);
            System.out.println("[DatabaseConnection]  Pool Size: " + config.getMaximumPoolSize());

        } catch (Exception e) {
            System.err.println("[DatabaseConnection] ❌ Lỗi khởi tạo database connection:");
            System.err.println("[DatabaseConnection] " + e.getMessage());
            e.printStackTrace();
            throw new RuntimeException("Không thể khởi tạo database connection pool", e);
        }
    }

    private DatabaseConnection() {} // Chống khởi tạo từ bên ngoài

    public static Connection getConnection() throws SQLException {
        return dataSource.getConnection();
    }

    private static String resolveJdbcUrl() {
        String directUrl = firstNonBlank(
                dotenv.get("AUCTION_DB_URL"),
                dotenv.get("DB_URL")
        );
        if (directUrl != null) {
            // ⚠️ Cảnh báo nếu URL vẫn chứa placeholder
            if (directUrl.contains("<") || directUrl.contains(">")) {
                System.err.println("[DatabaseConnection] ⚠️  CẢNH BÁO: AUCTION_DB_URL vẫn chứa placeholder '<>'");
                System.err.println("[DatabaseConnection] ⚠️  Hãy sửa .env file với hostname cloud thực tế!");
                System.err.println("[DatabaseConnection] ⚠️  Ví dụ: jdbc:mysql://your-cloud-host.com:3306/auction_system");
            }
            return directUrl;
        }

        String host = firstNonBlank(
                dotenv.get("AUCTION_DB_HOST"),
                dotenv.get("DB_HOST")
        );
        String port = firstNonBlank(
                dotenv.get("AUCTION_DB_PORT"),
                dotenv.get("DB_PORT")
        );
        String name = firstNonBlank(
                dotenv.get("AUCTION_DB_NAME"),
                dotenv.get("DB_NAME")
        );

        if (host == null || name == null) {
            System.out.println("[DatabaseConnection] ℹ️  Không tìm thấy env vars, sử dụng default local URL");
            return DEFAULT_JDBC_URL;
        }

        String resolvedPort = port == null ? "3306" : port;
        return "jdbc:mysql://" + host + ":" + resolvedPort + "/" + name;
    }

    private static String resolveDbUsername() {
        return firstNonBlank(
                dotenv.get("AUCTION_DB_USERNAME"),
                dotenv.get("DB_USER"),
                dotenv.get("DB_USERNAME"),
                DEFAULT_USERNAME
        );
    }

    private static String resolveDbPassword() {
        return firstNonBlank(
                dotenv.get("AUCTION_DB_PASSWORD"),
                dotenv.get("DB_PASSWORD"),
                DEFAULT_PASSWORD
        );
    }

    private static String firstNonBlank(String... values) {
        if (values == null) {
            return null;
        }
        for (String value : values) {
            if (value != null && !value.isBlank()) {
                return value;
            }
        }
        return null;
    }
}

package com.auction.manage;

import com.auction.network.ClientSession;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.CopyOnWriteArrayList;

/**
 * LiveRoomManage: Quản lý tập trung tất cả socket connections theo phòng (auctionId)
 *
 * Nguồn: Đề xuất kiến trúc LiveRoom thay thế Observer Pattern
 * Lợi ích:
 * - Broadcast message đến tất cả clients trong phòng dễ dàng
 * - Hỗ trợ 1 user nhiều connections (mobile + web)
 * - Clear separation of concerns: Auction chỉ focus logic, broadcast ở đây
 * - Thread-safe với ConcurrentHashMap + CopyOnWriteArrayList
 */
public class LiveRoomManage {
    private static volatile LiveRoomManage instance;

    // Key: auctionId, Value: List<ClientSession> đang theo dõi phiên
    private final Map<String, CopyOnWriteArrayList<ClientSession>> rooms
        = new ConcurrentHashMap<>();

    private LiveRoomManage() {}

    /**
     * Singleton pattern - Double-checked locking
     */
    public static LiveRoomManage getInstance() {
        LiveRoomManage temp = instance;
        if (temp == null) {
            synchronized (LiveRoomManage.class) {
                temp = instance;
                if (temp == null) {
                    temp = instance = new LiveRoomManage();
                }
            }
        }
        return temp;
    }

    /**
     * Join vào phòng đấu giá (Subscribe)
     * - Tạo room nếu chưa tồn tại
     * - Thêm client vào danh sách subscribers
     */
    public void joinRoom(String auctionId, ClientSession clientSession) {
        if (auctionId == null || clientSession == null) return;

        rooms.compute(auctionId, (key, room) -> {
            if (room == null) room = new CopyOnWriteArrayList<>();
            if (!room.contains(clientSession)) {
                room.add(clientSession);
                System.out.println("[LiveRoom] ✅ Client JOIN phiên " + auctionId);
            }
            return room; // Trả list đã update ngược lại vào Map
        });
    }

    /**
     * Rút khỏi phòng đấu giá (Unsubscribe)
     * - Xóa client khỏi danh sách -> ngắt kế nối khi đóng tab liveroom, hoac mất mạng
     * - Xóa room nếu trống (dọn dẹp bộ nhớ)
     */
    public void leaveRoom(String auctionId, ClientSession clientSession) {
        if (auctionId == null || clientSession == null) return;

        // Tính toán lại giá trị của phòng này trong trạng thái khóa an toàn
        rooms.computeIfPresent(auctionId, (key, room) -> {
            room.remove(clientSession);
            System.out.println("[LiveRoom] ❌ Client LEAVE phiên " + auctionId);

            // Nếu List rỗng, trả về null -> ConcurrentHashMap sẽ TỰ ĐỘNG XÓA key này!
            return room.isEmpty() ? null : room;
        });
    }

    /**
     * Phát sóng message đến tất cả clients trong phòng (Broadcast)
     * - Thread-safe: CopyOnWriteArrayList cho phép iterate an toàn khi add/remove
     * - Nếu gửi lỗi, tự động xóa client khỏi phòng
     */
    public void broadcast(String auctionId, String jsonMessage) {
        if (auctionId == null || jsonMessage == null) {
            return;
        }

        CopyOnWriteArrayList<ClientSession> room = rooms.get(auctionId);
        if (room == null || room.isEmpty()) {
            return; // Không có ai trong phòng
        }

        System.out.println("[LiveRoom]  Broadcast tới " + room.size()
            + " clients ở phiên " + auctionId);

        // Iterate từ CopyOnWriteArrayList - thread-safe
        for (ClientSession client : room) {
            try {
                client.sendMessage(jsonMessage);
            } catch (Exception e) {
                // Nếu gửi lỗi (client disconnect), tự động xóa khỏi phòng
                System.err.println("[LiveRoom] ⚠️ Gửi message lỗi tới "
                    + client.getUserId() + ": " + e.getMessage());
                leaveRoom(auctionId, client);
            }
        }
    }

    /**
     * Lấy số lượng clients trong phòng (for monitoring)
     */
    public int getRoomSize(String auctionId) {
        CopyOnWriteArrayList<ClientSession> room = rooms.get(auctionId);
        return (room != null) ? room.size() : 0;
    }

    /**
     * Lấy tất cả phòng đang hoạt động (for monitoring)
     */
    public int getTotalRooms() {
        return rooms.size();
    }

    /**
     * Xóa toàn bộ clients khỏi phòng (khi phiên kết thúc)
     * - Gọi khi finalizeAuction hoặc cancelAuction để dọn dẹp
     */
    public void clearRoom(String auctionId) {
        CopyOnWriteArrayList<ClientSession> room = rooms.remove(auctionId);
        if (room != null) {
            room.clear();
            System.out.println("[LiveRoom] Phòng " + auctionId + " đã bị xóa");
        }
    }
}

package com.auction.manage;

import com.auction.dto.BidTransactionDTO;
import com.auction.dto.SocketResponse;
import com.auction.network.ClientSession;
import com.auction.server.event.AuctionEvent;
import com.auction.server.event.AuctionEventType;
import com.auction.server.event.AuctionObserver;
import com.google.gson.Gson;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.CopyOnWriteArrayList;

/**
 * ============================================================
 * LiveRoomManage - Quản lý Socket Connections & Broadcast Events
 * ============================================================
 *
 * TRƯỚC: Quản lý tập trung tất cả socket connections theo phòng (auctionId)
 *        Chỉ có method: joinRoom(), leaveRoom(), broadcast()
 *
 * BÂY GIỜ (Refactored with Observer Pattern):
 * - Implement AuctionObserver để lắng nghe sự kiện từ AuctionEventBus
 * - Khi nhận event, tự động broadcast đến tất cả clients trong phòng
 * - Giải phóng AuctionService khỏi trách nhiệm quản lý client notifications
 *
 * Lợi ích của cách này:
 * ✅ Decoupling: AuctionService không cần biết về ClientSession
 * ✅ Scalability: Dễ thêm các Observer khác (NotificationService, AnalyticsService)
 * ✅ Maintainability: Tất cả broadcast logic tập trung ở 1 chỗ
 * ✅ Thread-safe: ConcurrentHashMap + CopyOnWriteArrayList
 *
 * SOLID Principles:
 * - Single Responsibility: Chỉ quản lý broadcast & client sessions
 * - Open/Closed: Mở cho extension (thực thi AuctionObserver), đóng cho modification
 * - Dependency Inversion: Phụ thuộc vào AuctionObserver interface, không concrete class
 */
public class LiveRoomManage implements AuctionObserver {
    private static volatile LiveRoomManage instance;

    // Key: auctionId, Value: List<ClientSession> đang theo dõi phiên
    private final Map<String, CopyOnWriteArrayList<ClientSession>> rooms
        = new ConcurrentHashMap<>();

    private LiveRoomManage() {}

    /**
     * Singleton pattern - Double-checked locking
     */
    public static LiveRoomManage getInstance() {
        LiveRoomManage temp = instance;
        if (temp == null) {
            synchronized (LiveRoomManage.class) {
                temp = instance;
                if (temp == null) {
                    temp = instance = new LiveRoomManage();
                }
            }
        }
        return temp;
    }

    /**
     * Join vào phòng đấu giá (Subscribe)
     * - Tạo room nếu chưa tồn tại
     * - Thêm client vào danh sách subscribers
     */
    public void joinRoom(String auctionId, ClientSession clientSession) {
        if (auctionId == null || clientSession == null) return;

        rooms.compute(auctionId, (key, room) -> {
            if (room == null) room = new CopyOnWriteArrayList<>();
            if (!room.contains(clientSession)) {
                room.add(clientSession);
                System.out.println("[LiveRoom] ✅ Client JOIN phiên " + auctionId);
            }
            return room; // Trả list đã update ngược lại vào Map
        });
    }

    /**
     * Rút khỏi phòng đấu giá (Unsubscribe)
     * - Xóa client khỏi danh sách -> ngắt kế nối khi đóng tab liveroom, hoac mất mạng
     * - Xóa room nếu trống (dọn dẹp bộ nhớ)
     */
    public void leaveRoom(String auctionId, ClientSession clientSession) {
        if (auctionId == null || clientSession == null) return;

        // Tính toán lại giá trị của phòng này trong trạng thái khóa an toàn
        rooms.computeIfPresent(auctionId, (key, room) -> {
            room.remove(clientSession);
            System.out.println("[LiveRoom] ❌ Client LEAVE phiên " + auctionId);

            // Nếu List rỗng, trả về null -> ConcurrentHashMap sẽ TỰ ĐỘNG XÓA key này!
            return room.isEmpty() ? null : room;
        });
    }

    /**
     * Phát sóng message đến tất cả clients trong phòng (Broadcast)
     * - Thread-safe: CopyOnWriteArrayList cho phép iterate an toàn khi add/remove
     * - Nếu gửi lỗi, tự động xóa client khỏi phòng
     */
    public void broadcast(String auctionId, String jsonMessage) {
        if (auctionId == null || jsonMessage == null) {
            return;
        }

        CopyOnWriteArrayList<ClientSession> room = rooms.get(auctionId);
        if (room == null || room.isEmpty()) {
            return; // Không có ai trong phòng
        }

        System.out.println("[LiveRoom]  Broadcast tới " + room.size()
            + " clients ở phiên " + auctionId);

        // Iterate từ CopyOnWriteArrayList - thread-safe
        for (ClientSession client : room) {
            try {
                client.sendMessage(jsonMessage);
            } catch (Exception e) {
                // Nếu gửi lỗi (client disconnect), tự động xóa khỏi phòng
                System.err.println("[LiveRoom] ⚠️ Gửi message lỗi tới "
                    + client.getUserId() + ": " + e.getMessage());
                leaveRoom(auctionId, client);
            }
        }
    }

    /**
     * Lấy số lượng clients trong phòng (for monitoring)
     */
    public int getRoomSize(String auctionId) {
        CopyOnWriteArrayList<ClientSession> room = rooms.get(auctionId);
        return (room != null) ? room.size() : 0;
    }

    /**
     * Lấy tất cả phòng đang hoạt động (for monitoring)
     */
    public int getTotalRooms() {
        return rooms.size();
    }

    /**
     * Xóa toàn bộ clients khỏi phòng (khi phiên kết thúc)
     * - Gọi khi finalizeAuction hoặc cancelAuction để dọn dẹp
     */
    public void clearRoom(String auctionId) {
        CopyOnWriteArrayList<ClientSession> room = rooms.remove(auctionId);
        if (room != null) {
            room.clear();
            System.out.println("[LiveRoom] Phòng " + auctionId + " đã bị xóa");
        }
    }
}
